const day = new Date().getDay();
const config = {
  1: { cible: 'enseigne', label: '🏢 Franchiseurs', url: 'https://www.thierrybismuth.com/reseaucommercialmultipotentiel' },
  3: { cible: 'candidat', label: '🙋 Candidats Multi-Potentiel', url: 'https://www.thierrybismuth.com/rejoindremulti-potentiel' },
  5: { cible: 'enseigne', label: '🏢 Franchiseurs', url: 'https://www.thierrybismuth.com/reseaucommercialmultipotentiel' }
};
const conf = config[day] || config[1];
return [{ json: conf }];

parameters.jsonBody:
={{ JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1500,
  messages: [{
    role: 'user',
    content: (() => {
      const anglesEnseignes = [
        "Angle COMPLÉMENTARITÉ : Multi-Potentiel ne remplace pas ce qui existe déjà (franchisés, commerciaux internes, flux entrants). Il vient couvrir les zones géographiques vides ou les verticales non exploitées. C'est du chiffre additionnel, pas une réorganisation.",
        "Angle TEST DE MARCHÉ : identifier un marché ne suffit pas. Avant d'investir 20 ou 50k€ dans une équipe commerciale, Multi-Potentiel permet de tester la demande terrain réelle — sans engagement structurel. On structure ensuite si ça tient.",
        "Angle AGILITÉ / SCALE-UP : belle traction mais impossible d'être partout. L'idée : garder le cœur en interne, externaliser les territoires périphériques via Multi-Potentiel. Découpage par région, par clientèle, par gamme produit — selon les priorités.",
        "Angle URGENCE CONCURRENTIELLE : la fenêtre d'opportunité est courte. La concurrence, les banques, le marché n'attendent pas. Multi-Potentiel comme accélérateur commercial immédiat — sans les délais et les coûts d'un recrutement classique."
      ];
      const anglesCandidats = [
        "Angle DIVERSIFICATION : représenter une seule enseigne, c'est mettre tous ses œufs dans le même panier. Multi-Potentiel permet de combiner plusieurs réseaux et de lisser les aléas d'un seul marché.",
        "Angle FILET DE SÉCURITÉ : entreprendre sans tout risquer. La mensualité Multi-Potentiel donne accès à un portefeuille multi-marques, des outils, une communauté — un investissement de départ amorti dès les premières missions.",
        "Angle VITESSE DE DÉMARRAGE : inutile d'attendre d'avoir le réseau parfait pour se lancer. Multi-Potentiel donne accès immédiatement à plusieurs enseignes et clientèles — on construit son activité en marchant.",
        "Angle LIBERTÉ CHOISIE : ni salarié, ni franchisé mono-enseigne. Un statut d'indépendant multi-cartes qui conserve la liberté de choisir ses enseignes, ses territoires, son rythme."
      ];
      const idx = new Date().getDay() % 4;
      const angles = $json.cible === 'enseigne' ? anglesEnseignes : anglesCandidats;
      const angleChoisi = angles[idx];
      return 'Tu es rédacteur pour un média spécialisé franchise et entrepreneuriat. Tu écris des posts LinkedIn et Instagram avec un angle éditorial : tu informes, tu questionnes, tu illustres une réalité du terrain. Pas de discours commercial, pas de superlatifs. Ton factuel, humain, légèrement journalistique.\n\nCible : ' + $json.label + '\nURL : ' + $json.url + '\nActualité franchise du moment (utilise comme contexte si pertinent) : ' + $json.actu_franchise + '\n\nANGLE ÉDITORIAL DU JOUR (base-toi sur cet angle en priorité) :\n' + angleChoisi + '\n\nContexte Multi-Potentiel de Thierry Bismuth :\nMulti-Potentiel est un réseau multi-enseignes dont les membres représentent plusieurs marques ou réseaux commerciaux simultanément (franchiseurs, réseaux de services, de distribution, partenaires commerciaux).\n\nRÈGLE ABSOLUE : ne jamais dénigrer la mono-franchise ni le modèle franchisé classique. Multi-Potentiel est une alternative complémentaire, pas un concurrent.\n\nSTYLE : accroche sous forme de question ou constat de terrain, 2-3 paragraphes courts, pas de liste à puces, pas de mot type découvrez ou révolutionnaire. Emojis discrets (2-3 max).\n\nCTA sobre en fin de post :\n📞 06 10 70 30 90\n📧 thierry@thierrybismuth.com\n🔗 ' + $json.url + '\n\nRéponds UNIQUEMENT avec un JSON valide, sans markdown ni backticks :\n{"linkedin_post": "[post LinkedIn avec hashtags]", "instagram_caption": "[version courte Instagram avec hashtags]"}';
    })()
  }]
}) }}

parameters.jsCode:
const text = $json.content[0].text.trim();
let parsed;
try {
  parsed = JSON.parse(text);
} catch(e) {
  const match = text.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : { linkedin_post: text, instagram_caption: text };
}
return [{ json: parsed }];

